Implement PromptValue - the typed runtime value that carries type info, world reference, session, and enables typed traversal.

Location: crates/baml-bridge/src/prompt/value.rs

```rust
use std::sync::Arc;

/// A typed value in the prompt rendering system
#[derive(Clone)]
pub struct PromptValue {
    /// The underlying runtime value
    pub value: BamlValue,

    /// The declared/inferred type
    pub ty: TypeIR,

    /// Reference to the type universe
    pub world: Arc<PromptWorld>,

    /// Per-render session (settings, ctx, depth)
    pub session: Arc<RenderSession>,

    /// Per-field renderer override (if any)
    pub override_renderer: Option<RendererOverride>,

    /// Path for error reporting (e.g., 'inputs.history.entries[3]')
    pub path: PromptPath,
}

impl PromptValue {
    /// Create a new PromptValue
    pub fn new(
        value: BamlValue,
        ty: TypeIR,
        world: Arc<PromptWorld>,
        session: Arc<RenderSession>,
        path: PromptPath,
    ) -> Self {
        Self {
            value,
            ty,
            world,
            session,
            override_renderer: None,
            path,
        }
    }

    /// Create with a field override
    pub fn with_override(mut self, override_renderer: RendererOverride) -> Self {
        self.override_renderer = Some(override_renderer);
        self
    }

    /// Get the effective type (resolves unions if needed)
    pub fn resolved_ty(&self) -> TypeIR {
        // Union resolution hook point - see UnionResolver bead
        todo!()
    }
}
```

PromptValue is Clone-friendly because Arc handles the heavy sharing. Path cloning is acceptable - it's small.

Implement get_value() for JinjaPromptValue - handles reserved keys and delegates to typed traversal.

Location: crates/baml-bridge/src/prompt/jinja.rs

```rust
impl Object for JinjaPromptValue {
    fn get_value(self: &Arc<Self>, key: &Value) -> Option<Value> {
        // Handle string keys
        if let Some(k) = key.as_str() {
            // Reserved keys
            match k {
                "render" => return Some(self.render_method()),
                "raw" => return Some(self.raw_value()),
                "__type__" => return Some(Value::from(self.pv.ty.diagnostic_repr().to_string())),
                "__path__" => return Some(Value::from(self.pv.path.to_string())),
                "__full_len__" => return Some(self.full_length()),
                _ => {}
            }

            // Class field access
            if self.is_class_like() {
                return self.pv.child_field(k)
                    .map(|child| child.as_jinja_value());
            }

            // Map key access
            if self.is_map_like() {
                return self.pv.child_map_value(k)
                    .map(|child| child.as_jinja_value());
            }
        }

        // Handle integer keys (list indexing)
        if let Ok(idx) = key.as_usize() {
            if self.is_list_like() {
                return self.pv.child_index(idx)
                    .map(|child| child.as_jinja_value());
            }
        }

        None
    }
}
```

Reserved keys:
- render: callable method for explicit style rendering
- raw: untyped value bypassing budget/traversal
- __type__: type diagnostic string
- __path__: current path for debugging
- __full_len__: actual length without caps

If a class has a field literally named 'render' or 'raw', access via .raw['render'].

Implement the field-level override renderer execution - the highest priority in the render chain.

Location: crates/baml-bridge/src/prompt/world.rs

```rust
impl PromptWorld {
    /// Try per-field override renderer
    fn try_field_override(&self, pv: &PromptValue, style: &str) -> Result<Option<RenderOutput>, RenderError> {
        let override_renderer = match &pv.override_renderer {
            Some(r) => r,
            None => return Ok(None),
        };

        match override_renderer {
            RendererOverride::Style { style: override_style } => {
                // Style override: only applies if requested style matches
                if style == *override_style || style == 'default' {
                    // Delegate to type-level renderer with override style
                    return self.try_type_renderer_with_style(pv, override_style);
                }
                Ok(None)
            }
            RendererOverride::Template { source, compiled_name } => {
                if style \!= 'default' && style \!= 'template' {
                    // Inline template only used for default/template style
                    return Ok(None);
                }

                // Execute inline template
                let template_name = compiled_name.as_ref()
                    .ok_or_else(|| RenderError {
                        message: 'field template not compiled'.to_string(),
                        // ...
                    })?;

                let result = self.execute_jinja_renderer(template_name, pv)?;
                Ok(Some(result))
            }
            RendererOverride::Func { f } => {
                if style \!= 'default' && style \!= 'func' {
                    return Ok(None);
                }
                let result = f(pv, &pv.session)?;
                Ok(Some(result))
            }
        }
    }
}
```

Field overrides come from #[render(...)] on Signature fields:
- #[render(style = "json")] -> use json renderer
- #[render(template = "...")] -> use inline template
- #[render(fn = "path")] -> call function
